function normalize(cells) {
    const minR = Math.min(...cells.map(p => p[0]));
    const minC = Math.min(...cells.map(p => p[1]));
    return new Set(cells.map(p => `${p[0] - minR},${p[1] - minC}`));
}
function rotate(cells, n) { return cells.map(p => [p[1], n - 1 - p[0]]); }
